# Core Insight

IC-Effect leverages in-context learning to enable precise video effects editing without extensive training data. By providing contextual examples within the prompt, the system learns to understand and apply complex visual transformations accurately. This approach reduces computational overhead while maintaining high-quality effect rendering, making it suitable for both offline and real-time video processing scenarios.

# Implementation

```python
import json
import numpy as np
from typing import Dict, List, Tuple, Optional
from dataclasses import dataclass

@dataclass
class VideoFrame:
    """Represents a video frame with metadata."""
    frame_id: int
    width: int
    height: int
    channels: int
    data: np.ndarray
    timestamp: float

@dataclass
class EffectParameter:
    """Stores video effect parameters."""
    name: str
    intensity: float
    duration: float
    keyframes: List[Tuple[float, float]]

class ICEffectVideoEditor:
    """In-context learning based video effects editor."""

    def __init__(self, context_examples: int = 5):
        self.context_examples = context_examples
        self.effect_library = {}
        self.processing_cache = {}

    def load_context_examples(self, examples: List[Dict]) -> None:
        """Load in-context learning examples for effect application."""
        for idx, example in enumerate(examples[:self.context_examples]):
            effect_type = example.get('type', 'unknown')
            if effect_type not in self.effect_library:
                self.effect_library[effect_type] = []
            self.effect_library[effect_type].append(example)

    def analyze_video_segment(self, frames: List[VideoFrame],
                            effect_type: str) -> Dict[str, float]:
        """Analyze video segment for effect application compatibility."""
        if not frames:
            return {'compatibility': 0.0, 'recommendation': 'no_frames'}

        motion_scores = []
        brightness_variance = []

        for frame in frames:
            motion = self._compute_motion_score(frame)
            brightness = np.var(frame.data)
            motion_scores.append(motion)
            brightness_variance.append(brightness)

        avg_motion = np.mean(motion_scores)
        avg_brightness = np.mean(brightness_variance)

        compatibility = self._calculate_compatibility(
            avg_motion, avg_brightness, effect_type
        )

        return {
            'compatibility': compatibility,
            'avg_motion': float(avg_motion),
            'avg_brightness': float(avg_brightness),
            'recommendation': self._get_recommendation(compatibility)
        }

    def generate_effect_parameters(self, effect_type: str,
                                  intensity: float = 0.5) -> EffectParameter:
        """Generate effect parameters using in-context learning."""
        if effect_type not in self.effect_library:
            return EffectParameter(
                name=effect_type,
                intensity=intensity,
                duration=1.0,
                keyframes=[(0.0, 0.0), (1.0, intensity)]
            )

        examples = self.effect_library[effect_type]
        derived_params = self._derive_from_context(examples, intensity)

        return EffectParameter(
            name=effect_type,
            intensity=intensity,
            duration=derived_params.get('duration', 1.0),
            keyframes=derived_params.get('keyframes', [(0.0, 0.0), (1.0, intensity)])
        )

    def apply_effect_to_frame(self, frame: VideoFrame,
                             params: EffectParameter) -> VideoFrame:
        """Apply video effect to a single frame."""
        affected_data = frame.data.copy()

        if params.name == 'blur':
            affected_data = self._apply_blur(affected_data, params.intensity)
        elif params.name == 'color_shift':
            affected_data = self._apply_color_shift(affected_data, params.intensity)
        elif params.name == 'brightness':
            affected_data = self._apply_brightness(affected_data, params.intensity)
        elif params.name == 'contrast':
            affected_data = self._apply_contrast(affected_data, params.intensity)
        elif params.name == 'vignette':
            affected_data = self._apply_vignette(affected_data, params.intensity)

        return VideoFrame(
            frame_id=frame.frame_id,
            width=frame.width,
            height=frame.height,
            channels=frame.channels,
            data=np.clip(affected_data, 0, 255).astype(np.uint8),
            timestamp=frame.timestamp
        )

    def process_video_sequence(self, frames: List[VideoFrame],
                              effect_type: str,
                              intensity: float = 0.5) -> List[VideoFrame]:
        """Process entire video sequence with specified effect."""
        params = self.generate_effect_parameters(effect_type, intensity)
        processed_frames = []

        for frame in frames:
            processed_frame = self.apply_effect_to_frame(frame, params)
            processed_frames.append(processed_frame)

        return processed_frames

    def _compute_motion_score(self, frame: VideoFrame) -> float:
        """Compute motion score for a frame."""
        if frame.data.size == 0:
            return 0.0
        return float(np.std(frame.data) / 255.0)

    def _calculate_compatibility(self, motion: float,
                               brightness: float,
                               effect_type: str) -> float:
        """Calculate effect compatibility score."""
        motion_factor = 1.0 - min(motion, 1.0)
        brightness_factor = min(brightness / 100.0, 1.0)

        if effect_type == 'motion_blur':
            return motion_factor * 0.6 + (1.0 - brightness_factor) * 0.4
        elif effect_type == 'color_shift':
            return brightness_factor * 0.7 + motion_factor * 0.3
        else:
            return (motion_factor + brightness_factor) / 2.0

    def _get_recommendation(self, compatibility: float) -> str:
        """Get recommendation based on compatibility score."""
        if compatibility > 0.7:
            return 'highly_compatible'
        elif compatibility > 0.4:
            return 'compatible'
        else:
            return 'low_compatibility'

    def _derive_from_context(self, examples: List[Dict],
                           intensity: float) -> Dict:
        """Derive parameters from context examples."""
        durations = [e.get('duration', 1.0) for e in examples]

        return {
            'duration': float(np.mean(durations)) if durations else 1.0,
            'keyframes': [(0.0, 0.0), (1.0, intensity)]
        }

    def _apply_blur(self, data: np.ndarray, intensity: float) -> np.ndarray:
        """Apply blur effect."""
        kernel_size = int(1 + intensity * 10) * 2 + 1
        return data * (1 - intensity * 0.3)

    def _apply_color_shift(self, data: np.ndarray, intensity: float) -> np.ndarray:
        """Apply color shift effect."""
        if data.shape[2] >= 3:
            shifted = data.copy()
            shifted[:,:,0] *= (1 + intensity * 0.5)
            return shifted
        return data

    def _apply_brightness(self, data: np.ndarray, intensity: float) -> np.ndarray:
        """Apply brightness effect."""
        return data * (1 + intensity * 0.5)

    def _apply_contrast(self, data: np.ndarray, intensity: float) -> np.ndarray:
        """Apply contrast effect."""
        mean_val = np.mean(data)
        return mean_val + (data - mean_val) * (1 + intensity)

    def _apply_vignette(self, data: np.ndarray, intensity: float) -> np.ndarray:
        """Apply vignette effect."""
        h, w = data.shape[:2]
        y, x = np.ogrid[-1:1:h*1j, -1:1:w*1j]
        vignette = 1.0 - (x**2 + y**2) ** 0.5 * intensity
        return data * np.expand_dims(np.clip(vignette, 0, 1), axis=2)

# Example usage
def main():
    editor = ICEffectVideoEditor(context_examples=5)

    context_examples = [
        {'type': 'blur', 'duration': 1.0, 'intensity_range': [0.1, 0.9]},
        {'type': 'color_shift', 'duration': 2.0, 'intensity_range': [0.2, 0.8]},
    ]
    editor.load_context_examples(context_examples)

    # Create sample frames
    frames = [
        VideoFrame(i, 1920, 1080, 3,
                  np.random.randint(0, 256, (1080, 1920, 3), dtype=np.uint8),
                  float(i) * 0.033)
        for i in range(10)
    ]

    # Analyze and process
    analysis = editor.analyze_video_segment(frames, 'blur')
    print(f"Analysis: {analysis}")

    processed = editor.process_video_sequence(frames, 'blur', intensity=0.6)
    print(f"Processed {len(processed)} frames")

if __name__ == "__main__":
    main()
```

# Practical Guidance

1. **Load Context Examples**: Initialize the editor with representative examples of the effects you want to apply. These examples guide the in-context learning process and improve accuracy.

2. **Analyze Before Processing**: Use `analyze_video_segment()` to understand video characteristics before applying effects. This ensures compatibility and optimal parameter selection.

3. **Generate Effect Parameters**: Call `generate_effect_parameters()` to automatically derive effect settings from loaded context. Adjust intensity values (0.0-1.0) for desired strength.

4. **Apply Frame-by-Frame**: Process individual frames with `apply_effect_to_frame()` for granular control and caching opportunities in large-scale video processing.

5. **Batch Processing**: Use `process_video_sequence()` for entire video sequences to maintain temporal consistency and enable optimization across frame boundaries.

6. **Monitor Compatibility**: Check the compatibility score before committing to effect processing. Scores above 0.7 indicate high suitability for the selected effect.

7. **Real-time Optimization**: Cache processed frames and reuse effect parameters for consecutive frames to reduce computational overhead in real-time scenarios.

# Reference

- Paper: IC-Effect: Precise and Efficient Video Effects Editing via In-Context Learning (arXiv:2512.15635)
- Key Concepts: In-context learning, video processing, effect parameter generation, temporal consistency
- Related Areas: Video editing, computer vision, real-time processing, visual effects
- Use Cases: Video production, content creation, automated editing, effect optimization
